import './Main.css'
import POST from '../Post/Post'
import React, { Component } from 'react'

export default class Main extends Component {
    render() {
        const { list, tag, listVisible } = this.props
        let array = []

        function params(index, i) {
            return list[i].tags.indexOf(tag.split(",")[index]) !== -1
        }
        if (this.props.userPosts) {//                                                    userPost - Account
            for (let i = 15; i < Object.keys(list).length; i++) {
                array.push(<POST key={this.props.list[i].id} x={true} list={this.props.list[i]} />)
            }
        } else if (listVisible.length === 0) {//                                        liatVisible === 0 - MAIN 
            for (let i = 0; i < Object.keys(list).length; i++) {
                array.push(<POST key={list[i].id} list={list[i]} />)
            }
        } else if (tag !== null) {//                                                     tag !== 0 - POSTWINDOWS
            for (let i = 0; i < Object.keys(list).length; i++) {
                if ((params(0, i) || params(1, i) || params(2, i) || params(3, i))) {
                    array.push(
                        <POST key={this.props.list[i].id} list={this.props.list[i]} />
                    )
                }
            }
        } else {//                                                                       listVisible - main === user
            for (let i = 0; i < Object.keys(list).length; i++) {
                if (list[i].tags.indexOf(listVisible.toLowerCase()) !== -1) {
                    array.push(<POST key={list[i].id} list={list[i]} />)
                }
            }
        }

        return (
            <div className="main-block">
                {array}
            </div>
        )
    }
}
